19	// setupApprovalHarness wires a gqlgen handler with the same CSRF / identity
20	// plumbing as the production server, plus a configurable auto-approve
21	// allowlist. The tsnetUser argument, when non-empty, is injected as the
22	// X-Tailscale-User header on every request — that is how production
23	// classifies a request as ts-net-originated, and the locked Story 15
24	// decision excludes such requests from auto-approve regardless of the
25	// allowlist contents.
26	func setupApprovalHarness(t *testing.T, allowlist []string, tsnetUser string) (http.Handler, *bead.Store, string) {
27		t.Helper()
28	
29		workDir, err := os.MkdirTemp("", "operator-prompt-approval-")
30		if err != nil {
31			t.Fatal(err)
32		}
33		t.Cleanup(func() { _ = os.RemoveAll(workDir) })
34	
35		ddxDir := filepath.Join(workDir, ".ddx")
36		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
37			t.Fatal(err)
38		}
39		cfg := "version: \"1.0\"\nbead:\n  id_prefix: \"op\"\n"
40		if err := os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(cfg), 0o644); err != nil {
41			t.Fatal(err)
42		}
43		store := bead.NewStore(ddxDir)
44		if err := store.Init(); err != nil {
45			t.Fatal(err)
46		}
47	
48		const token = "test-csrf-token-deadbeef"
49		cache := ddxgraphql.NewMemoryIdempotencyCache()
50		csrf := ddxgraphql.NewStaticCSRFTokenStoreWithToken(token)
51	
52		gql := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
53			Resolvers: &ddxgraphql.Resolver{
54				WorkingDir:                         workDir,
55				CSRFTokens:                         csrf,
56				OperatorPromptIdempotency:          cache,
57				OperatorPromptAutoApproveAllowlist: append([]string(nil), allowlist...),
58			},
59			Directives: ddxgraphql.DirectiveRoot{},
60		}))
61		gql.AddTransport(transport.POST{})
62		gql.AddTransport(transport.GET{})
63	
64		wrapped := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
65			if tsnetUser != "" {
66				r.Header.Set("X-Tailscale-User", tsnetUser)
67			}
68			r = r.WithContext(ddxgraphql.WithHTTPRequest(r.Context(), r))
69			gql.ServeHTTP(w, r)
70		})
71		return wrapped, store, token
72	}
