74	func postGQL(t *testing.T, h http.Handler, csrfToken string, query string, vars map[string]any) map[string]json.RawMessage {
75		t.Helper()
76		body, _ := json.Marshal(map[string]any{
77			"query":     query,
78			"variables": vars,
79		})
80		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(body))
81		req.Header.Set("Content-Type", "application/json")
82		if csrfToken != "" {
83			req.Header.Set(ddxgraphql.CSRFHeaderName, csrfToken)
84		}
85		w := httptest.NewRecorder()
86		h.ServeHTTP(w, req)
87		var resp map[string]json.RawMessage
88		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
89			t.Fatalf("invalid JSON: %v\nbody: %s", err, w.Body.String())
90		}
91		return resp
92	}
