94	const submitMutation = `mutation Submit($input: OperatorPromptSubmitInput!) {
95		operatorPromptSubmit(input: $input) {
96			bead { id status }
97			deduplicated
98			autoApproved
99		}
100	}`
101	
102	const approveMutation = `mutation Approve($id: ID!) {
103		operatorPromptApprove(id: $id) {
104			bead { id status }
105		}
106	}`
107	
108	const cancelMutation = `mutation Cancel($id: ID!) {
109		operatorPromptCancel(id: $id) {
110			bead { id status }
111		}
112	}`
113	
114	func submitProposed(t *testing.T, h http.Handler, token, prompt, key string, autoApprove *bool) (string, map[string]json.RawMessage) {
115		t.Helper()
116		input := map[string]any{
117			"prompt":         prompt,
118			"idempotencyKey": key,
119		}
120		if autoApprove != nil {
121			input["autoApprove"] = *autoApprove
122		}
123		resp := postGQL(t, h, token, submitMutation, map[string]any{"input": input})
124		if errs, ok := resp["errors"]; ok {
125			t.Fatalf("submit returned errors: %s", errs)
126		}
127		var data struct {
128			OperatorPromptSubmit struct {
129				Bead struct {
130					ID     string `json:"id"`
131					Status string `json:"status"`
132				} `json:"bead"`
133				Deduplicated bool `json:"deduplicated"`
134				AutoApproved bool `json:"autoApproved"`
135			} `json:"operatorPromptSubmit"`
136		}
137		if err := json.Unmarshal(resp["data"], &data); err != nil {
138			t.Fatalf("parse: %v", err)
139		}
140		if data.OperatorPromptSubmit.Bead.ID == "" {
141			t.Fatal("expected bead ID")
142		}
143		return data.OperatorPromptSubmit.Bead.ID, resp
144	}
