146	// AC #1 (mutations exist) + AC #4 happy: manual approve transitions
147	// proposed → open and emits the operator_prompt_approve audit event.
148	func TestOperatorPromptApprove_Happy(t *testing.T) {
149		h, store, token := setupApprovalHarness(t, []string{ddxgraphql.OperatorPromptAllowlistLocalhostSentinel}, "")
150		id, _ := submitProposed(t, h, token, "approve me", "k1", nil)
151	
152		resp := postGQL(t, h, token, approveMutation, map[string]any{"id": id})
153		if errs, ok := resp["errors"]; ok {
154			t.Fatalf("approve returned errors: %s", errs)
155		}
156		var data struct {
157			OperatorPromptApprove struct {
158				Bead struct {
159					ID     string `json:"id"`
160					Status string `json:"status"`
161				} `json:"bead"`
162			} `json:"operatorPromptApprove"`
163		}
164		if err := json.Unmarshal(resp["data"], &data); err != nil {
165			t.Fatalf("parse: %v", err)
166		}
167		if got := data.OperatorPromptApprove.Bead.Status; got != bead.StatusOpen {
168			t.Errorf("status after approve: want %q, got %q", bead.StatusOpen, got)
169		}
170		events, err := store.EventsByKind(id, ddxgraphql.OperatorPromptApproveEventKind)
171		if err != nil {
172			t.Fatal(err)
173		}
174		if len(events) != 1 {
175			t.Errorf("want 1 approve audit event, got %d", len(events))
176		}
177	}
