213	// AC #2 denied: an empty allowlist blocks operatorPromptApprove even for
214	// the localhost identity that submitted the prompt. The bead remains in
215	// the proposed status and no approve audit event is appended.
216	func TestOperatorPromptApprove_DeniedEmptyAllowlist(t *testing.T) {
217		h, store, token := setupApprovalHarness(t, nil, "")
218		id, _ := submitProposed(t, h, token, "needs approval", "k1", nil)
219	
220		resp := postGQL(t, h, token, approveMutation, map[string]any{"id": id})
221		errs, ok := resp["errors"]
222		if !ok {
223			t.Fatalf("expected approve to be denied, got data %s", resp["data"])
224		}
225		var parsed []struct {
226			Message string `json:"message"`
227		}
228		if err := json.Unmarshal(errs, &parsed); err != nil {
229			t.Fatal(err)
230		}
231		if len(parsed) == 0 || !contains(parsed[0].Message, "allowlist") {
232			t.Errorf("denial must reference the allowlist, got %q", parsed)
233		}
234		persisted, err := store.Get(id)
235		if err != nil {
236			t.Fatal(err)
237		}
238		if persisted.Status != bead.StatusProposed {
239			t.Errorf("bead must remain proposed on denial, got %q", persisted.Status)
240		}
241		events, _ := store.EventsByKind(id, ddxgraphql.OperatorPromptApproveEventKind)
242		if len(events) != 0 {
243			t.Errorf("want 0 approve audit events on denial, got %d", len(events))
244		}
245	}
