247	// AC #3 denied: ts-net identities are NEVER eligible for auto-approve, even
248	// when the allowlist contains the localhost sentinel. The submission
249	// succeeds (bead is created in proposed) but autoApproved=false.
250	func TestOperatorPromptSubmit_AutoApproveDeniedForTsnet(t *testing.T) {
251		// Allowlist contains both the localhost sentinel (so localhost may
252		// auto-approve) AND the ts-net actor (so the ts-net peer is permitted
253		// to submit at all). The locked Story 15 decision still denies the
254		// auto-approve transition for ts-net regardless of allowlist contents.
255		h, store, token := setupApprovalHarness(t, []string{ddxgraphql.OperatorPromptAllowlistLocalhostSentinel, "alice@example.com"}, "alice@example.com")
256	
257		autoApprove := true
258		id, raw := submitProposed(t, h, token, "do a ts-net thing", "k1", &autoApprove)
259	
260		var data struct {
261			OperatorPromptSubmit struct {
262				AutoApproved bool `json:"autoApproved"`
263				Bead         struct {
264					Status string `json:"status"`
265				} `json:"bead"`
266			} `json:"operatorPromptSubmit"`
267		}
268		if err := json.Unmarshal(raw["data"], &data); err != nil {
269			t.Fatal(err)
270		}
271		if data.OperatorPromptSubmit.AutoApproved {
272			t.Error("ts-net identity must NEVER be auto-approved (locked decision)")
273		}
274		if data.OperatorPromptSubmit.Bead.Status != bead.StatusProposed {
275			t.Errorf("ts-net submission must remain proposed, got %q", data.OperatorPromptSubmit.Bead.Status)
276		}
277		events, _ := store.EventsByKind(id, ddxgraphql.OperatorPromptApproveEventKind)
278		if len(events) != 0 {
279			t.Errorf("auto-approve audit event must NOT be appended for ts-net, got %d", len(events))
280		}
281	}
