355	// AC #1: approve / cancel reject beads that are not in the proposed status
356	// (e.g. an already-cancelled bead cannot be re-approved). Ensures the
357	// state machine cannot be backed up via these mutations.
358	func TestOperatorPromptApprove_RejectsNonProposed(t *testing.T) {
359		h, _, token := setupApprovalHarness(t, []string{ddxgraphql.OperatorPromptAllowlistLocalhostSentinel}, "")
360		id, _ := submitProposed(t, h, token, "double-action", "k1", nil)
361	
362		// Cancel first so it leaves the proposed status.
363		if resp := postGQL(t, h, token, cancelMutation, map[string]any{"id": id}); resp["errors"] != nil {
364			t.Fatalf("setup cancel errored: %s", resp["errors"])
365		}
366	
367		resp := postGQL(t, h, token, approveMutation, map[string]any{"id": id})
368		if _, ok := resp["errors"]; !ok {
369			t.Fatal("approve on cancelled bead must error")
370		}
371	}
