373	// AC #4: per-project allowlist enforced — a ts-net peer not on the
374	// allow_identities allowlist receives a 403 on operatorPromptSubmit and no
375	// bead is created. This is the "default empty allowlist → ts-net peers see
376	// read-only UI" guarantee enforced server-side.
377	func TestOperatorPromptSubmit_TsnetNotInAllowlistRejected(t *testing.T) {
378		h, _, token := setupApprovalHarness(t, nil, "bob@example.com")
